B.It=new A.bw(B.tb,["\u0935\u094b\u091f\u092c\u0921\u0940 \u092e\u0947\u0902 \u0906\u092a\u0915\u093e \u0938\u094d\u0935\u093e\u0917\u0924 \u0939\u0948","\u0938\u0941\u0930\u0915\u094d\u0937\u093f\u0924 \u0930\u093f\u092e\u094b\u091f \u0935\u094b\u091f\u093f\u0902\u0917 \u0938\u093f\u0938\u094d\u091f\u092e","EPIC / \u0935\u094b\u091f\u0930 \u0906\u0908\u0921\u0940 \u0926\u0930\u094d\u091c \u0915\u0930\u0947\u0902","\u0909\u0926\u093e. LOCAL123 \u092f\u093e REMOTE123","\u0906\u0908\u0921\u0940 \u0938\u0924\u094d\u092f\u093e\u092a\u093f\u0924 \u0915\u0930\u0947\u0902","\u0915\u0943\u092a\u092f\u093e \u090f\u0915 \u0906\u0908\u0921\u0940 \u0926\u0930\u094d\u091c \u0915\u0930\u0947\u0902","\u092a\u093e\u0924\u094d\u0930\u0924\u093e \u091c\u093e\u0902\u091a","\u0928\u093e\u092e: ","\u0906\u092f\u0941: ","\u0928\u093f\u0930\u094d\u0935\u093e\u091a\u0928 \u0915\u094d\u0937\u0947\u0924\u094d\u0930: ","\u0935\u094b\u091f \u0926\u0947\u0928\u0947 \u0915\u0947 \u092f\u094b\u0917\u094d\u092f \u0928\u0939\u0940\u0902","\u0935\u094b\u091f \u0926\u0947\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0906\u092a\u0915\u0940 \u0906\u092f\u0941 18 \u092f\u093e \u0905\u0927\u093f\u0915 \u0939\u094b\u0928\u0940 \u091a\u093e\u0939\u093f\u090f\u0964","\u0935\u093e\u092a\u0938","\u0935\u094b\u091f \u0926\u0947\u0928\u0947 \u0915\u0947 \u092f\u094b\u0917\u094d\u092f","\u0938\u094d\u0925\u093e\u0928 \u0938\u0924\u094d\u092f\u093e\u092a\u093f\u0924 \u0915\u0930\u0947\u0902","\u0935\u094b\u091f\u093f\u0902\u0917 \u092e\u094b\u0921","\u0906\u092a\u0915\u093e \u0938\u094d\u0925\u093e\u0928: ","\u0932\u094b\u0915\u0932 \u0935\u094b\u091f\u093f\u0902\u0917 \u092e\u094b\u0921","\u0930\u093f\u092e\u094b\u091f \u0935\u094b\u091f\u093f\u0902\u0917 \u092e\u094b\u0921","\u0906\u092a \u0905\u092a\u0928\u0947 \u0917\u0943\u0939 \u0928\u093f\u0930\u094d\u0935\u093e\u091a\u0928 \u0915\u094d\u0937\u0947\u0924\u094d\u0930 \u092e\u0947\u0902 \u0939\u0948\u0902\u0964 \u0915\u0943\u092a\u092f\u093e \u0905\u092a\u0928\u0947 \u0938\u094d\u0925\u093e\u0928\u0940\u092f \u092c\u0942\u0925 \u092a\u0930 \u091c\u093e\u090f\u0902\u0964","\u0906\u092a \u0905\u092a\u0928\u0947 \u0928\u093f\u0930\u094d\u0935\u093e\u091a\u0928 \u0915\u094d\u0937\u0947\u0924\u094d\u0930 \u0915\u0947 \u092c\u093e\u0939\u0930 \u0939\u0948\u0902\u0964 \u0915\u0943\u092a\u092f\u093e AVN \u0915\u0947 \u092e\u093e\u0927\u094d\u092f\u092e \u0938\u0947 \u0906\u0917\u0947 \u092c\u0922\u093c\u0947\u0902\u0964","\u091c\u093e\u0930\u0940 \u0930\u0916\u0947\u0902","\u0938\u094d\u0925\u093e\u0928\u0940\u092f \u0935\u094b\u091f\u093f\u0902\u0917","\u0930\u093f\u092e\u094b\u091f \u0935\u094b\u091f\u093f\u0902\u0917","\u0938\u094d\u0925\u093e\u0928\u0940\u092f \u092c\u0942\u0925 \u092a\u0930 \u091c\u093e\u090f\u0902","AVN \u0915\u0947\u0902\u0926\u094d\u0930 \u092a\u0930 \u091c\u093e\u090f\u0902","1. \u0905\u092a\u0928\u0947 \u0928\u093f\u0930\u094d\u0927\u093e\u0930\u093f\u0924 \u092e\u0924\u0926\u093e\u0928 \u092c\u0942\u0925 \u092a\u0930 \u091c\u093e\u090f\u0902\u0964\n2. \u0905\u0927\u093f\u0915\u093e\u0930\u0940 \u0915\u094b \u0905\u092a\u0928\u0940 \u0906\u0908\u0921\u0940 \u0926\u093f\u0916\u093e\u090f\u0902\u0964\n3. \u0935\u094b\u091f\u093f\u0902\u0917 \u092e\u0936\u0940\u0928 \u0915\u0940 \u0913\u0930 \u092c\u0922\u093c\u0947\u0902\u0964","1. \u0928\u093f\u0915\u091f\u0924\u092e AVN \u092a\u0930 \u0938\u094d\u0932\u0949\u091f \u092c\u0941\u0915 \u0915\u0930\u0947\u0902\u0964\n2. \u0905\u092a\u0928\u0947 \u0938\u092e\u092f \u092a\u0930 AVN \u092a\u0930 \u091c\u093e\u090f\u0902\u0964\n3. \u092c\u093e\u092f\u094b\u092e\u0947\u091f\u094d\u0930\u093f\u0915 \u0938\u0924\u094d\u092f\u093e\u092a\u0928 \u092a\u0942\u0930\u093e \u0915\u0930\u0947\u0902\u0964","\u0938\u0924\u094d\u092f\u093e\u092a\u0928 \u0936\u0941\u0930\u0942 \u0915\u0930\u0947\u0902","AVN \u0938\u0924\u094d\u092f\u093e\u092a\u0928 \u0915\u0947 \u0932\u093f\u090f \u0906\u0917\u0947 \u092c\u0922\u093c\u0947\u0902","\u0938\u0924\u094d\u092f\u093e\u092a\u0928","\u092c\u0947\u0938\u093f\u0915 \u0906\u0908\u0921\u0940 \u091a\u0947\u0915","\u092c\u093e\u092f\u094b\u092e\u0947\u091f\u094d\u0930\u093f\u0915 \u092b\u093f\u0902\u0917\u0930\u092a\u094d\u0930\u093f\u0902\u091f \u0938\u094d\u0915\u0948\u0928","\u0938\u0924\u094d\u092f\u093e\u092a\u093f\u0924 \u0915\u0930\u0947\u0902","\u092e\u0924\u0926\u093e\u0924\u093e \u0938\u0942\u091a\u0940 \u092e\u093f\u0932\u093e\u0928","\u092b\u0947\u0938 \u0932\u093e\u0907\u0935\u0928\u0947\u0938 \u091a\u0947\u0915","\u0938\u0924\u094d\u092f\u093e\u092a\u0928 \u092a\u0942\u0930\u093e \u0939\u094b \u0930\u0939\u093e \u0939\u0948...","\u0905\u092a\u0928\u093e \u0935\u094b\u091f \u0926\u0947\u0902","\u0935\u094b\u091f \u0926\u0947\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u090f\u0915 \u092a\u094d\u0930\u0924\u0940\u0915 \u091a\u0941\u0928\u0947\u0902:","\u0935\u094b\u091f \u091c\u092e\u093e \u0915\u0930\u0947\u0902","\u0935\u094b\u091f \u0938\u092b\u0932\u0924\u093e\u092a\u0942\u0930\u094d\u0935\u0915 \u091c\u092e\u093e \u0915\u093f\u092f\u093e \u0917\u092f\u093e!","\u0906\u092a\u0915\u093e \u0935\u094b\u091f \u0938\u0941\u0930\u0915\u094d\u0937\u093f\u0924 \u0930\u0942\u092a \u0938\u0947 \u090f\u0928\u094d\u0915\u094d\u0930\u093f\u092a\u094d\u091f\u0947\u0921 \u0939\u0948\u0964\n\u090f\u0915 \u0935\u094d\u092f\u0915\u094d\u0924\u093f = \u090f\u0915 \u0935\u094b\u091f","\u092a\u0941\u0937\u094d\u091f\u093f\u0915\u0930\u0923 \u0906\u0908\u0921\u0940","\u0935\u093e\u092a\u0938 \u0939\u094b\u092e \u092a\u0930","\u092d\u093e\u0937\u093e"],t.li)
